import { EmbeddedScene, SceneFlexLayout, SceneFlexItem, VizPanel, SceneTimeRange } from '@grafana/scenes';

export function buildCpuScene() {
  return new EmbeddedScene({
    $timeRange: new SceneTimeRange({ from: 'now-1h', to: 'now' }),
    body: new SceneFlexLayout({
      children: [
        new SceneFlexItem({
          body: new VizPanel({
            pluginId: 'timeseries',
            title: 'CPU Usage',
            datasource: { uid: 'prometheus-uid' },
            fieldConfig: { defaults: { unit: 'percent' }, overrides: [] },
          }),
        }),
      ],
    }),
  });
}

// Grafana mixed-datasource panel target config (panel JSON)
// This is Grafana's unique edge — correlate metrics + logs in one panel
{
  "datasource": { "type": "mixed", "uid": "-- Mixed --" },
  "targets": [
    {
      "datasource": { "type": "prometheus", "uid": "${prometheus_uid}" },
      "expr": "rate(http_requests_total{status=~'5..'}[5m])",
      "legendFormat": "Error rate"
    },
    {
      "datasource": { "type": "loki", "uid": "${loki_uid}" },
      "expr": "{app=\"api\"} |= \"exception\" | logfmt | level=\"error\"",
      "legendFormat": "Error logs"
    }
  ]
}
